What will be the output of the following code if you enter 4 and 3 for b and e respectively?
#include <iostream>
using namespace std;
int main() {
  int b, e, r = 1;
  cout << "enter b and e";
  cin >> b >> e;
  for (int i = 1; i <= e; i++) {
    r = r * b;
  }
  cout << r;
  return 0;
}

